"use strict";(globalThis.webpackChunkbowrain_docs=globalThis.webpackChunkbowrain_docs||[]).push([[8938],{6198(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>i,default:()=>l,frontMatter:()=>o,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"id":"architecture-decisions/021-brand-knowledge-graph","title":"AD-021: The brand knowledge graph","description":"Summary","source":"@site/docs/architecture-decisions/021-brand-knowledge-graph.md","sourceDirName":"architecture-decisions","slug":"/architecture-decisions/021-brand-knowledge-graph","permalink":"/web/bowrain/docs/architecture-decisions/021-brand-knowledge-graph","draft":false,"unlisted":false,"editUrl":"https://github.com/neokapi/neokapi/tree/main/bowrain/web/docs/docs/architecture-decisions/021-brand-knowledge-graph.md","tags":[],"version":"current","sidebarPosition":21,"frontMatter":{"id":"021-brand-knowledge-graph","sidebar_position":21,"title":"AD-021: The brand knowledge graph"},"sidebar":"forDevelopersSidebar","previous":{"title":"AD-020: Governance, audit, and rollback","permalink":"/web/bowrain/docs/architecture-decisions/020-governance-audit-rollback"},"next":{"title":"Overview","permalink":"/web/bowrain/docs/notes/index"}}');var r=t(1325),a=t(9705);const o={id:"021-brand-knowledge-graph",sidebar_position:21,title:"AD-021: The brand knowledge graph"},i="AD-021: The brand knowledge graph",d={},c=[{value:"Summary",id:"summary",level:2},{value:"Context",id:"context",level:2},{value:"Decision",id:"decision",level:2},{value:"One node type: the concept",id:"one-node-type-the-concept",level:3},{value:"Markets",id:"markets",level:3},{value:"The concept story",id:"the-concept-story",level:3},{value:"Observations \u2014 what others say",id:"observations--what-others-say",level:3},{value:"Comments",id:"comments",level:3},{value:"Experiments: change-sets and pilots",id:"experiments-change-sets-and-pilots",level:3},{value:"Tiered governance",id:"tiered-governance",level:3},{value:"Blast radius as a first-class query",id:"blast-radius-as-a-first-class-query",level:3},{value:"Surfaces",id:"surfaces",level:3},{value:"Framework and platform split",id:"framework-and-platform-split",level:3},{value:"Consequences",id:"consequences",level:2},{value:"Future: the stakeholder review app (design only)",id:"future-the-stakeholder-review-app-design-only",level:2},{value:"Cross-references",id:"cross-references",level:2}];function h(e){const n={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.header,{children:(0,r.jsx)(n.h1,{id:"ad-021-the-brand-knowledge-graph",children:"AD-021: The brand knowledge graph"})}),"\n",(0,r.jsx)(n.h2,{id:"summary",children:"Summary"}),"\n",(0,r.jsxs)(n.p,{children:["Bowrain models a workspace's brand language as a knowledge graph whose nodes\nare ",(0,r.jsx)(n.strong,{children:"concepts"})," \u2014 the language-neutral units already used by the termbase \u2014\nand whose edges are typed, time- and market-scoped ",(0,r.jsx)(n.strong,{children:"relations"})," between them.\nBrand vocabulary rules, terminology, observations about how others use a term,\ndiscussion threads, and revision history all attach to the same concept, so a\nsingle page can tell the whole story of a term: where it came from, what it\nreplaced, where it is banned, how it is said in every market, and what it would\ncost to change. (Compliance scores are reported per project and locale on the\ndashboard, not folded into an individual concept.)"]}),"\n",(0,r.jsxs)(n.p,{children:["Changes to the graph follow a tiered governance model. Ordinary curation is\ndirect and audited. Governed transitions \u2014 banning a term, changing a preferred\nterm, merging an experiment \u2014 travel through a ",(0,r.jsx)(n.strong,{children:"change-set"}),": a named,\nreviewable draft of graph and voice edits whose ",(0,r.jsx)(n.strong,{children:"blast radius"})," over existing\ncontent is computed before anyone approves it. A change-set can optionally be\n",(0,r.jsx)(n.strong,{children:"piloted"})," on selected content streams before it merges, so a what-if becomes\na measured experiment rather than a leap."]}),"\n",(0,r.jsxs)(n.p,{children:["The navigator surfaces as a unified ",(0,r.jsx)(n.strong,{children:"Brand"})," hub in the web and desktop apps\n(Concepts, Voice, Experiments, Activity, Dashboard). Its Concepts section is a\nsearchable ",(0,r.jsx)(n.strong,{children:"concept list"})," that opens, per concept, a ",(0,r.jsx)(n.strong,{children:"dashboard"})," \u2014 terms,\ngeography, constraints, a local relations widget, a timeline, observations, and\ndiscussion \u2014 not a whole-graph canvas. Governed terminology reaches a project's\nlocal files through ordinary sync (",(0,r.jsx)(n.code,{children:"kapi pull"}),"/",(0,r.jsx)(n.code,{children:"kapi push"}),"), and assistants read\nit through MCP tools, so CI gates and AI assistants consume the same governed\ntruth the hub shows."]}),"\n",(0,r.jsx)(n.h2,{id:"context",children:"Context"}),"\n",(0,r.jsx)(n.p,{children:"Brand language decays through drift, not decisions: a competitor name slips\ninto a tagline, a renamed product survives in old docs, a market keeps a term\nthe company retired. Before this decision, bowrain held the raw material in\nthree disconnected systems. The termbase modeled concepts with per-locale terms\nand lifecycle statuses but persisted no relations between concepts. Brand voice\nprofiles enforced vocabulary as flat term strings with no link to the concepts\nthose strings denote. A graph store existed with SKOS-aligned relation labels\nand temporal validity on edges, but nothing wrote to it and no surface read\nfrom it."}),"\n",(0,r.jsxs)(n.p,{children:["The result was that the questions a brand steward actually asks had no home:\n",(0,r.jsx)(n.em,{children:"what replaced this term, and when?"})," ",(0,r.jsx)(n.em,{children:"Is this banned everywhere or only in\nGermany?"})," ",(0,r.jsx)(n.em,{children:"Who decided that, and what did they discuss?"})," ",(0,r.jsx)(n.em,{children:"If we rename this\nconcept, how much published content moves?"})," Each question touches identity\n(concepts), history (versions and audit), scope (markets and time), and\nconsequence (content impact) at once \u2014 which is exactly the shape of a graph\nwith governance, not three flat tables."]}),"\n",(0,r.jsx)(n.h2,{id:"decision",children:"Decision"}),"\n",(0,r.jsx)(n.h3,{id:"one-node-type-the-concept",children:"One node type: the concept"}),"\n",(0,r.jsxs)(n.p,{children:["The termbase ",(0,r.jsx)(n.code,{children:"Concept"})," is the single node of the brand knowledge graph. Brand\nvocabulary is not a parallel system: a forbidden term is a concept whose term\ncarries ",(0,r.jsx)(n.code,{children:"forbidden"})," status, and the brand profile's vocabulary rules reference\nconcepts by ID (",(0,r.jsx)(n.code,{children:"TermRule.ConceptID"}),"). Concept-less rules exist only for\nstandalone kapi use, where a profile file travels without a workspace graph;\non the platform every rule \u2014 including rules promoted by the\ncorrection-learning loop (AD-019) \u2014 is concept-backed."]}),"\n",(0,r.jsxs)(n.p,{children:["Relations are persisted with the termbase as first-class records. The relation\nvocabulary reuses the framework's SKOS-aligned labels: hierarchy (",(0,r.jsx)(n.code,{children:"BROADER"}),",\n",(0,r.jsx)(n.code,{children:"NARROWER"}),", ",(0,r.jsx)(n.code,{children:"PART_OF"}),", ",(0,r.jsx)(n.code,{children:"HAS_PART"}),", ",(0,r.jsx)(n.code,{children:"RELATED"}),"), succession (",(0,r.jsx)(n.code,{children:"REPLACED_BY"}),"),\nguidance (",(0,r.jsx)(n.code,{children:"USE_INSTEAD"}),"), cross-scheme equivalence (",(0,r.jsx)(n.code,{children:"EXACT_MATCH"}),",\n",(0,r.jsx)(n.code,{children:"CLOSE_MATCH"}),"), and brand stance (",(0,r.jsx)(n.code,{children:"COMPETITOR"}),"). Each relation may carry a\n",(0,r.jsx)(n.code,{children:"Validity"}),": a half-open time interval plus free tags evaluated against a\nquery-time scope. The graph can therefore be asked ",(0,r.jsx)(n.em,{children:"as of"})," a date or ",(0,r.jsx)(n.em,{children:"within"}),"\na market, and the same edge can be true in one market and absent in another."]}),"\n",(0,r.jsx)(n.h3,{id:"markets",children:"Markets"}),"\n",(0,r.jsxs)(n.p,{children:["A ",(0,r.jsx)(n.strong,{children:"market"})," is a workspace-defined scope \u2014 a name plus the locales it covers\n(for example ",(0,r.jsx)(n.code,{children:"dach"})," covering ",(0,r.jsx)(n.code,{children:"de-DE"}),", ",(0,r.jsx)(n.code,{children:"de-AT"}),", ",(0,r.jsx)(n.code,{children:"de-CH"}),"). Markets give the free\nvalidity tags a stable vocabulary: terms and relations scoped with\n",(0,r.jsx)(n.code,{children:"market: dach"})," are interpreted, filtered, and rendered consistently across\nevery surface. A term's status may differ per market by carrying market-scoped\nvalidity; a concept page renders the per-market truth side by side."]}),"\n",(0,r.jsx)(n.h3,{id:"the-concept-story",children:"The concept story"}),"\n",(0,r.jsxs)(n.p,{children:["Every concept has a ",(0,r.jsx)(n.strong,{children:"story"}),': a single chronological timeline merging its\nrevision history (every edit produces an immutable revision snapshot whose\nsummary records the term-status transitions and the relations gained or lost),\nthe observations recorded against it, its comment threads, and the change-sets\nthat affected it. The story answers "how did this term get here" without\narchaeology across systems. Revisions are the per-concept slice of the\nhash-chained audit trail (AD-020); compliance scores are not part of the story \u2014\nthose are aggregated per project and locale on the dashboard.']}),"\n",(0,r.jsx)(n.h3,{id:"observations--what-others-say",children:"Observations \u2014 what others say"}),"\n",(0,r.jsxs)(n.p,{children:["An ",(0,r.jsx)(n.strong,{children:"observation"})," attaches external evidence to a concept: a competitor's\nphrasing, customer language from support tickets, a style-guide citation, a\nregulatory requirement. Observations carry a kind, a quote, a source, an\noptional locale and market, and provenance. They are evidence, not rules: they\ninform proposals and appear in the story, but they enforce nothing."]}),"\n",(0,r.jsx)(n.h3,{id:"comments",children:"Comments"}),"\n",(0,r.jsx)(n.p,{children:"Concepts carry threaded comments with @mentions, reusing the platform's\nmention-notification machinery. Discussion lives where the decision will be\nmade \u2014 on the concept or on the change-set under review \u2014 and resolved threads\nremain part of the story."}),"\n",(0,r.jsx)(n.h3,{id:"experiments-change-sets-and-pilots",children:"Experiments: change-sets and pilots"}),"\n",(0,r.jsxs)(n.p,{children:["A ",(0,r.jsx)(n.strong,{children:"change-set"})," is a named draft of edits to the graph and to brand voice\nvocabulary: create or update concepts, add or remove terms, change a term's\nstatus, add or remove relations, add or remove concept-backed voice rules. Ops\naccumulate in a draft; nothing touches the live graph until merge. A change-set\nmoves through ",(0,r.jsx)(n.code,{children:"draft \u2192 in_review \u2192 approved \u2192 merged"}),", or is ",(0,r.jsx)(n.code,{children:"abandoned"}),"; every\ntransition is audited and notified."]}),"\n",(0,r.jsx)(n.p,{children:"Two capabilities make a change-set an experiment rather than paperwork:"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Blast radius."})," At any point, the platform evaluates the draft against\nstored content across the workspace: which blocks in which projects,\ncollections, streams, and locales would be newly flagged or resolved, with\nword counts as a proxy for re-translation effort and sample blocks for\ninspection. This generalizes the single-rule preview of AD-019 to arbitrary\ngraph edits. Nothing is persisted by the preview."]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Pilots."})," A change-set may be bound to one or more content streams as a\npilot. While the pilot is active, term lookups, enforcement, and brand checks\nin those streams resolve through the draft (a stream-scoped shadow over the\nworkspace graph, using the termbase's existing stream inheritance), so real\ncontent and real checks exercise the proposal. Merging the change-set applies\nthe ops to the workspace graph and retires the shadows; abandoning it retires\nthe shadows untouched."]}),"\n"]}),"\n",(0,r.jsx)(n.h3,{id:"tiered-governance",children:"Tiered governance"}),"\n",(0,r.jsxs)(n.p,{children:["Edits are classified as ",(0,r.jsx)(n.strong,{children:"ordinary"})," or ",(0,r.jsx)(n.strong,{children:"governed"}),". Ordinary edits \u2014\ndefinitions, notes, observations, comments, proposed terms, non-status term\nmetadata \u2014 apply directly, produce a revision, and land in the audit chain.\nGoverned edits \u2014 setting a term's status to ",(0,r.jsx)(n.code,{children:"forbidden"})," or ",(0,r.jsx)(n.code,{children:"preferred"}),",\nremoving such a status, ",(0,r.jsx)(n.code,{children:"REPLACED_BY"})," relations, concept-backed voice rule\nchanges, and merging any change-set \u2014 require a change-set with at least one\napproval from someone other than its author (separation of duties, enforced\nwith the same machinery as AD-020). Term status transitions are additionally\nvalidated against a transition policy in the framework \u2014 for example, a\nforbidden term cannot silently return to preferred without passing through a\ngoverned transition."]}),"\n",(0,r.jsx)(n.p,{children:"The pending-approval queue is deliberately simple: a list of proposals, each\nwith a human-readable summary, a blast radius, and an approve/reject decision.\nThis is the contract a future stakeholder review app consumes (see below)."}),"\n",(0,r.jsx)(n.h3,{id:"blast-radius-as-a-first-class-query",children:"Blast radius as a first-class query"}),"\n",(0,r.jsxs)(n.p,{children:["Beyond change-sets, every concept exposes ",(0,r.jsx)(n.em,{children:"where it is used"}),': occurrences of\nits terms across stored blocks, grouped by project, collection, stream, and\nlocale. This powers the "consequences" half of the navigator \u2014 a steward sees\nthe footprint of a concept before proposing anything.']}),"\n",(0,r.jsx)(n.h3,{id:"surfaces",children:"Surfaces"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Web and desktop"})," present one ",(0,r.jsx)(n.strong,{children:"Brand"})," hub with five sections: Concepts\n(a searchable concept list that opens a per-concept dashboard), Voice\n(profiles and the correction loop), Experiments (change-sets, reviews,\npilots), Activity (the brand-scoped event timeline), and Dashboard\n(compliance, drift, coverage, pending decisions). There is no whole-graph\nvisualization: a concept's relations are read and edited as a ",(0,r.jsx)(n.strong,{children:"local\nwidget"}),' on its dashboard \u2014 the concept plus the concepts one hop away, with\nlarge families collapsed to an "N related" summary and a click to navigate \u2014\nso the surface never has to lay out or guard an unbounded graph. The desktop\napp remains a working copy of the server: it proxies the same REST surface,\nand its views stay fresh through React Query\'s stale-time and\nrefetch-on-focus; concepts and relations are edited inline against the\nserver, never authored offline.']}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"CLI and CI."})," Governed terminology rides ordinary project sync through the\nbowrain plugin. ",(0,r.jsx)(n.code,{children:"kapi pull"})," snapshots the workspace's governed concepts and\ntheir relations into the project's local termbase, and \u2014 decisive for CI \u2014\n",(0,r.jsx)(n.code,{children:"kapi verify --terms"})," then gates offline against the same truth the hub\nshows. ",(0,r.jsx)(n.code,{children:"kapi push"})," sends local concept edits back: ordinary edits apply\ndirectly through the concept endpoints, while governed edits (a banned or\npreferred term, an un-forbidding, a ",(0,r.jsx)(n.code,{children:"REPLACED_BY"})," relation, a concept delete)\nare bundled into one submitted change-set proposal, so the separation of\nduties holds whether an edit originates in the hub or from a project."]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"MCP."})," Assistants navigate the workspace's concepts through MCP read tools\n(concept search, concept story, experiment status), complementing the\nexisting brand and terminology tools."]}),"\n"]}),"\n",(0,r.jsx)(n.h3,{id:"framework-and-platform-split",children:"Framework and platform split"}),"\n",(0,r.jsx)(n.p,{children:"The framework (Apache) owns what any terminology system needs: the concept and\nterm model, persisted relations with validity, the status-transition policy,\nmatching and enforcement tools, and import/export. Bowrain (AGPL) owns\ngovernance and collaboration: markets, observations, comments, revisions,\nchange-sets, reviews, pilots, blast radius over stored content, events, audit,\nand every surface. The framework remains free of platform types; the platform\nconsumes framework types directly."}),"\n",(0,r.jsx)(n.h2,{id:"consequences",children:"Consequences"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"The termbase becomes the system of record for brand vocabulary; brand\nprofiles keep enforcement semantics but delegate identity to concepts. Two\npreviously independent stores can no longer drift apart silently."}),"\n",(0,r.jsx)(n.li,{children:'Relations and validity make queries scope-dependent: every consumer of term\ndata must decide its scope (time, market, stream). Defaults are "now,\neverywhere, main".'}),"\n",(0,r.jsx)(n.li,{children:"Change-sets introduce a second write path to the graph. Direct writes and\nmerges serialize through the same store, and merge re-validates ops against\ncurrent revisions so stale drafts conflict loudly instead of clobbering."}),"\n",(0,r.jsx)(n.li,{children:"Pilot shadows add stream-scoped state that must be cleaned up on merge and\nabandon; the implementation owns that lifecycle, not the user."}),"\n",(0,r.jsx)(n.li,{children:"Blast radius over a whole workspace is bounded work but not free; it runs\non demand and reports per-project partial progress rather than blocking."}),"\n"]}),"\n",(0,r.jsx)(n.h2,{id:"future-the-stakeholder-review-app-design-only",children:"Future: the stakeholder review app (design only)"}),"\n",(0,r.jsx)(n.p,{children:'The governed-proposal queue is the natural seam for a lightweight stakeholder\nsurface: a phone-first app where a brand owner reviews one card per proposal \u2014\nthe summary in plain words, the blast radius as one number and one chart, the\ndiscussion highlights \u2014 and swipes to approve or reject, with an optional\n"discuss" gesture that drops a comment into the thread. Everything it needs\nexists in this decision\'s API: list pending change-sets, read summary and\nblast radius, post a review verdict, post a comment. Scoped session grants\n(AD-016) bound such an app to review-only permissions. Push notifications map\nto the existing notification dispatcher. No additional server concepts are\nrequired, which is the point: the swipe app is a view over governance, not a\nsecond governance system. It is intentionally not implemented now.'}),"\n",(0,r.jsx)(n.h2,{id:"cross-references",children:"Cross-references"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"AD-006 \u2014 graph concept storage (the dormant store this decision activates as\na projection target)."}),"\n",(0,r.jsx)(n.li,{children:"AD-019 \u2014 the correction-learning loop; promotions now create concept-backed\nrules."}),"\n",(0,r.jsx)(n.li,{children:"AD-020 \u2014 governance, audit, and rollback; change-set approvals reuse SoD and\nthe audit chain."}),"\n",(0,r.jsx)(n.li,{children:"AD-005 \u2014 streams; pilots bind change-sets to content streams."}),"\n",(0,r.jsxs)(n.li,{children:["Implementation detail (schemas, routes, op types):\n",(0,r.jsx)(n.a,{href:"/web/bowrain/docs/notes/knowledge-graph-data-model",children:"knowledge graph data model"}),"."]}),"\n"]})]})}function l(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(h,{...e})}):h(e)}},9705(e,n,t){t.d(n,{R:()=>o,x:()=>i});var s=t(489);const r={},a=s.createContext(r);function o(e){const n=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function i(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:o(e.components),s.createElement(a.Provider,{value:n},e.children)}}}]);